(function(){var b64="";var bin=atob(b64);var bytes=new Uint8Array(bin.length);for(var i=0;i<bin.length;i++)bytes[i]=bin.charCodeAt(i);var text=new TextDecoder("utf-8").decode(bytes);monaco.editor.getModels()[0].setValue(text);return({chars:text.length,lines:text.split(String.fromCharCode(10)).length});})()